            const fifthGradeRadix = (timeDiff) => parseFloat(Math.pow(timeDiff, 1 / 5));

            const postPubTimestamp = 1774440023;

            const now = Math.floor(Date.now() / 1000); // Current timestamp in seconds
            const oneDayInSeconds = 86400; // Number of seconds in a day

            const postPubDiff = now - postPubTimestamp;

            let shares = 0;
            if (postPubDiff < oneDayInSeconds) {
              console.log('intraday');
              shares = parseInt(fifthGradeRadix(postPubDiff) * 200) - 200;
            } else {
              console.log('extraday');
              const now = new Date();
              const startOfDay = new Date(now.getFullYear(), now.getMonth(), now.getDate());
              const secondsSinceStart = Math.floor((now - startOfDay) / 1000);
              shares = ( 0 || 0 ) + ( parseInt(fifthGradeRadix(secondsSinceStart) * 200) - 200 );
            }

		    // approximation
		    shares = parseInt(shares / 200);

            console.log('shares', shares);
            // Add thousand separator
            const formatShares = (shares) => shares.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ".");

let formattedShares = formatShares(shares);

            document.getElementById('post_shares_counter').innerHTML = formattedShares == 'NaN' ? '0' : formattedShares;

Riccardo Mantica


                Pubblicato il 25 mar 2026

Sono passati appena un paio di mesi dall’ultimo aggiornamento della Classe S, e Mercedes torna a lavorare sulla sua ammiraglia. Questa volta mettendo mano alla versione più esclusiva. La Maybach. Il risultato? Un restyling che punta ancora più in alto, senza stravolgere. Ma con una certa ostinazione per il lusso. Il suo DNA.

Un lusso che si fa notare (anche troppo?)

A colpire subito è la quantità di richiami visivi al marchio Maybach. I loghi “Double M” spuntano un po’ ovunque, dalle prese d’aria anteriori fino ai cerchi. Persino il montante C ora si illumina, così come la classica stella a tre punte sul cofano. La griglia cresce del 20% e integra una firma luminosa, accompagnata da una scritta Maybach retroilluminata che difficilmente passa inosservata.

Mercedes, però, parla di “autorità discreta”. Una definizione che potrebbe far discutere, considerando anche i proiettori laterali che segnalano chiaramente la presenza della versione più costosa della Classe S. E poi ci sono i fari, anteriori e posteriori, con il motivo della stella ripetuto quasi a voler ribadire il concetto: questa non è una berlina qualsiasi.

